+  auto replayed_messages = subscriber_future_.get();
+  ASSERT_THAT(replayed_messages, SizeIs(2));
+  ASSERT_THAT(replayed_messages[0], Eq("Hello World 1"));
+  ASSERT_THAT(replayed_messages[1], Eq("Hello World 2"));
+
+  rclcpp::shutdown();
+}

