+
+  start_recording();
+  publish_messages({message_to_publish});
+  stop_recording();
+
+  auto recorded_messages = get_messages(database_name_);
+
+  ASSERT_THAT(recorded_messages, SizeIs(1));
+  ASSERT_THAT(recorded_messages[0], Eq(message_to_publish));
+}

